class Solution:
    def largestNumber(self, nums) -> str:
        strs = [str(x) for x in nums]
        n = len(strs)
        for i in range(n):
            for j in range(i + 1, n):
                if strs[j] + strs[i] > strs[i] + strs[j]:
                    strs[i], strs[j] = strs[j], strs[i]
        result = ''.join(strs)
        return '0' if result[0] == '0' else result

